module CancelIngestionResponse =
  struct
    type nonrec t =
      {
      arn: Arn.t option
        [@ocaml.doc "The Amazon Resource Name (ARN) for the data ingestion."];
      ingestionId: IngestionId.t option
        [@ocaml.doc "An ID for the ingestion."];
      requestId: String_.t option
        [@ocaml.doc "The Amazon Web Services request ID for this operation."];
      status: StatusCode.t option
        [@ocaml.doc "The HTTP status of the request."]}
    type nonrec error =
      [ `AccessDeniedException of AccessDeniedException.t 
      | `InternalFailureException of InternalFailureException.t 
      | `InvalidParameterValueException of InvalidParameterValueException.t 
      | `ResourceExistsException of ResourceExistsException.t 
      | `ResourceNotFoundException of ResourceNotFoundException.t 
      | `ThrottlingException of ThrottlingException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?arn =
      fun ?ingestionId ->
        fun ?requestId ->
          fun ?status -> fun () -> { arn; ingestionId; requestId; status }
    let error_of_json name json =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_json json)
      | "InternalFailureException" ->
          `InternalFailureException (InternalFailureException.of_json json)
      | "InvalidParameterValueException" ->
          `InvalidParameterValueException
            (InvalidParameterValueException.of_json json)
      | "ResourceExistsException" ->
          `ResourceExistsException (ResourceExistsException.of_json json)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_json json)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_xml xml)
      | "InternalFailureException" ->
          `InternalFailureException (InternalFailureException.of_xml xml)
      | "InvalidParameterValueException" ->
          `InvalidParameterValueException
            (InvalidParameterValueException.of_xml xml)
      | "ResourceExistsException" ->
          `ResourceExistsException (ResourceExistsException.of_xml xml)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_xml xml)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDeniedException e ->
          `Assoc
            [("error", (`String "AccessDeniedException"));
            ("details", (AccessDeniedException.to_json e))]
      | `InternalFailureException e ->
          `Assoc
            [("error", (`String "InternalFailureException"));
            ("details", (InternalFailureException.to_json e))]
      | `InvalidParameterValueException e ->
          `Assoc
            [("error", (`String "InvalidParameterValueException"));
            ("details", (InvalidParameterValueException.to_json e))]
      | `ResourceExistsException e ->
          `Assoc
            [("error", (`String "ResourceExistsException"));
            ("details", (ResourceExistsException.to_json e))]
      | `ResourceNotFoundException e ->
          `Assoc
            [("error", (`String "ResourceNotFoundException"));
            ("details", (ResourceNotFoundException.to_json e))]
      | `ThrottlingException e ->
          `Assoc
            [("error", (`String "ThrottlingException"));
            ("details", (ThrottlingException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Arn", (Option.map x.arn ~f:Arn.to_value));
        ("IngestionId", (Option.map x.ingestionId ~f:IngestionId.to_value));
        ("RequestId", (Option.map x.requestId ~f:String_.to_value));
        ("Status", (Option.map x.status ~f:StatusCode.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let status =
        (Option.map ~f:StatusCode.of_xml) (Xml.child xml_arg0 "Status") in
      let requestId =
        (Option.map ~f:String_.of_xml) (Xml.child xml_arg0 "RequestId") in
      let ingestionId =
        (Option.map ~f:IngestionId.of_xml) (Xml.child xml_arg0 "IngestionId") in
      let arn = (Option.map ~f:Arn.of_xml) (Xml.child xml_arg0 "Arn") in
      make ?status ?requestId ?ingestionId ?arn ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let status = field_map json__ "Status" StatusCode.of_json in
      let requestId = field_map json__ "RequestId" String_.of_json in
      let ingestionId = field_map json__ "IngestionId" IngestionId.of_json in
      let arn = field_map json__ "Arn" Arn.of_json in
      make ?status ?requestId ?ingestionId ?arn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc "Cancels an ongoing ingestion of data into SPICE."]
module CapabilityState =
  struct
    type nonrec t =
      | DENY 
      | Non_static_id of string 
    let make i = i
    let to_string = function | DENY -> "DENY" | Non_static_id s -> s
    let of_string = function | "DENY" -> DENY | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration CapabilityState" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"CapabilityState" j)
    let to_json = simple_to_json to_value
  end
