module TypeCastFormat =
  struct
    type nonrec t = string
    let context_ = "TypeCastFormat"
    let make i =
      let open Result in ok_or_failwith (check_string_max i ~max:32); i
    let of_string x = x
    let to_value x = `String x
    let to_query v = to_query to_value v
    let to_header x = x
    let of_xml = Xml.string_data_exn ~context:context_
    let of_json j = string_of_json ~kind:"TypeCastFormat" j
    let to_json = simple_to_json to_value
  end
module ColumnDataType =
  struct
    type nonrec t =
      | STRING 
      | INTEGER 
      | DECIMAL 
      | DATETIME 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | STRING -> "STRING"
      | INTEGER -> "INTEGER"
      | DECIMAL -> "DECIMAL"
      | DATETIME -> "DATETIME"
      | Non_static_id s -> s
    let of_string =
      function
      | "STRING" -> STRING
      | "INTEGER" -> INTEGER
      | "DECIMAL" -> DECIMAL
      | "DATETIME" -> DATETIME
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration ColumnDataType" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"ColumnDataType" j)
    let to_json = simple_to_json to_value
  end
module ColumnDataSubType =
  struct
    type nonrec t =
      | FLOAT 
      | FIXED 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function | FLOAT -> "FLOAT" | FIXED -> "FIXED" | Non_static_id s -> s
    let of_string =
      function | "FLOAT" -> FLOAT | "FIXED" -> FIXED | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string
        (string_of_xml ~kind:"enumeration ColumnDataSubType" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"ColumnDataSubType" j)
    let to_json = simple_to_json to_value
  end
module CastColumnTypeOperation =
  struct
    type nonrec t =
      {
      columnName: ColumnName.t [@ocaml.doc "Column name."];
      newColumnType: ColumnDataType.t [@ocaml.doc "New column data type."];
      subType: ColumnDataSubType.t option
        [@ocaml.doc
          "The sub data type of the new column. Sub types are only available for decimal columns that are part of a SPICE dataset."];
      format: TypeCastFormat.t option
        [@ocaml.doc
          "When casting a column from string to datetime type, you can supply a string in a format supported by Quick Sight to denote the source data format."]}
    let context_ = "CastColumnTypeOperation"
    let make ?subType =
      fun ?format ->
        fun ~columnName ->
          fun ~newColumnType ->
            fun () -> { subType; format; columnName; newColumnType }
    let to_value x =
      structure_to_value
        [("ColumnName", (Some (ColumnName.to_value x.columnName)));
        ("NewColumnType", (Some (ColumnDataType.to_value x.newColumnType)));
        ("SubType", (Option.map x.subType ~f:ColumnDataSubType.to_value));
        ("Format", (Option.map x.format ~f:TypeCastFormat.to_value))]
