    let of_xml xml_arg0 =
      let format =
        (Option.map ~f:TypeCastFormat.of_xml) (Xml.child xml_arg0 "Format") in
      let subType =
        (Option.map ~f:ColumnDataSubType.of_xml)
          (Xml.child xml_arg0 "SubType") in
      let newColumnType =
        ColumnDataType.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "NewColumnType") in
      let columnName =
        ColumnName.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "ColumnName") in
      make ?format ?subType ~newColumnType ~columnName ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let format = field_map json__ "Format" TypeCastFormat.of_json in
      let subType = field_map json__ "SubType" ColumnDataSubType.of_json in
      let newColumnType =
        field_map_exn json__ "NewColumnType" ColumnDataType.of_json in
      let columnName = field_map_exn json__ "ColumnName" ColumnName.of_json in
      make ?format ?subType ~newColumnType ~columnName ()
